// compact JS retry with full jitter
async function retryWithJitter(fn, opts = {}) {
  const { maxAttempts = 5, base = 100, maxDelay = 10000 } = opts;
  for (let i = 1; i <= maxAttempts; i++) {
    try { return await fn(); } catch (err) {
      if (i === maxAttempts || !isRetryable(err)) throw err;
      const expo = Math.min(maxDelay, base * 2 ** (i - 1));
      const delay = Math.floor(Math.random() * expo);
      await new Promise(r => setTimeout(r, delay));
    }
  }
}

function isRetryable(err) {
  return err && (err.code === 'ETIMEDOUT' || [429,502,503,504].includes(err.status || 0));
}
